#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define EXPAND_RATE 2
#define AMB_TEMP 80.0f

__kernel void hotspot(int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      int col,
                      int row,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    __local float temp_tile[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_tile[BLOCK_SIZE][BLOCK_SIZE];

    const int tx = get_local_id(0);
    const int ty = get_local_id(1);
    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - iteration * EXPAND_RATE;
    const int small_block_rows = BLOCK_SIZE - iteration * EXPAND_RATE;

    const int blkX = small_block_cols * bx - borderCols;
    const int blkY = small_block_rows * by - borderRows;

    const int xidx = blkX + tx;
    const int yidx = blkY + ty;

    const int in_range = (xidx >= 0 && xidx < col && yidx >= 0 && yidx < row);
    const int index = yidx * col + xidx;

    temp_tile[ty][tx] = in_range ? temp_src[index] : 0.0f;
    power_tile[ty][tx] = in_range ? power[index] : 0.0f;

    barrier(CLK_LOCAL_MEM_FENCE);

    const float step_local = step * 0.001f;   // match source OpenMP behavior
    const float Cap_1 = step_local / Cap;

    for (int i = 0; i < iteration; i++) {
        float new_temp = temp_tile[ty][tx];
        int compute = 0;

        if (tx >= i + 1 && tx <= BLOCK_SIZE - i - 2 &&
            ty >= i + 1 && ty <= BLOCK_SIZE - i - 2 &&
            in_range) {
            compute = 1;

            const float tc = temp_tile[ty][tx];
            const float pw = power_tile[ty][tx];

            if (yidx == 0 && xidx == 0) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty][tx + 1] - tc) / Rx +
                                         (temp_tile[ty + 1][tx] - tc) / Ry +
                                         (AMB_TEMP - tc) / Rz);
            } else if (yidx == 0 && xidx == col - 1) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty][tx - 1] - tc) / Rx +
                                         (temp_tile[ty + 1][tx] - tc) / Ry +
                                         (AMB_TEMP - tc) / Rz);
            } else if (yidx == row - 1 && xidx == col - 1) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty][tx - 1] - tc) / Rx +
                                         (temp_tile[ty - 1][tx] - tc) / Ry +
                                         (AMB_TEMP - tc) / Rz);
            } else if (yidx == row - 1 && xidx == 0) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty][tx + 1] - tc) / Rx +
                                         (temp_tile[ty - 1][tx] - tc) / Ry +
                                         (AMB_TEMP - tc) / Rz);
            } else if (yidx == 0) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty][tx + 1] + temp_tile[ty][tx - 1] - 2.0f * tc) / Rx +
                                         (temp_tile[ty + 1][tx] - tc) / Ry +
                                         (AMB_TEMP - tc) / Rz);
            } else if (xidx == col - 1) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty + 1][tx] + temp_tile[ty - 1][tx] - 2.0f * tc) / Ry +
                                         (temp_tile[ty][tx - 1] - tc) / Rx +
                                         (AMB_TEMP - tc) / Rz);
            } else if (yidx == row - 1) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty][tx + 1] + temp_tile[ty][tx - 1] - 2.0f * tc) / Rx +
                                         (temp_tile[ty - 1][tx] - tc) / Ry +
                                         (AMB_TEMP - tc) / Rz);
            } else if (xidx == 0) {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty + 1][tx] + temp_tile[ty - 1][tx] - 2.0f * tc) / Ry +
                                         (temp_tile[ty][tx + 1] - tc) / Rx +
                                         (AMB_TEMP - tc) / Rz);
            } else {
                new_temp = tc + Cap_1 * (pw +
                                         (temp_tile[ty + 1][tx] + temp_tile[ty - 1][tx] - 2.0f * tc) / Ry +
                                         (temp_tile[ty][tx + 1] + temp_tile[ty][tx - 1] - 2.0f * tc) / Rx +
                                         (AMB_TEMP - tc) / Rz);
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        if (compute) {
            temp_tile[ty][tx] = new_temp;
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (tx >= borderCols && tx < BLOCK_SIZE - borderCols &&
        ty >= borderRows && ty < BLOCK_SIZE - borderRows &&
        in_range) {
        temp_dst[index] = temp_tile[ty][tx];
    }
}
